-- Enrichment marathon batch: Helium, Indico, Infisical, InfluxDB Cloud, INGInious, Inkscape, Inngest, Insightly

-- в”Ђв”Ђ Helium в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source student planner by HeliumEdu that tracks classes, assignments, and grades with real-time GPA calculations on web, iOS, and Android.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Helium Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Helium is a free, open-source student planner with real-time grade tracking, at-risk alerts, and calendar sync. See features, pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Helium, built by HeliumEdu and often referred to as the Helium Student Planner, is a free and open-source academic planning application that helps students track classes, assignments, grades, and notes in a single color-coded workspace across web, iOS, and Android. It was created by independent developer Alex Laird, who also maintains other open-source tools like pyngrok, and is sustained entirely through community support on Patreon and GitHub Sponsors rather than venture funding or a commercial pricing model. Helium is the spiritual successor to Get Organized, an earlier cross-platform Java desktop application by the same developer that was downloaded more than 25,000 times by students since around 2010; Helium rebuilt that concept as a modern cloud-synced web and mobile product. Architecturally, Helium is a full-stack web application with native companion apps for iOS and Android, backed by a REST API (the codebase is published under the heliumedu GitHub organization), and it supports two-way calendar synchronization with Google Calendar, Apple Calendar, and generic iCal feeds so assignments and class schedules stay current across a student's existing tools. The core feature set centers on academic organization: a multi-view calendar (Month, Week, Day, Agenda) for classes and assignments, drag-and-drop scheduling, a dedicated Todos view for checklist-style task management, and a rich, searchable notebook that links notes directly to specific classes or assignments with support for headings, lists, quotes, and links. Its standout capability is real-time grade management вЂ” Helium recalculates GPA and per-class grades instantly as work is entered, flags 'at-risk' classes when scores fall below a student-defined threshold, shows a 'progress versus pace' indicator (ahead, on track, or behind), breaks grades down by assignment category, and offers a 'what grade do I need' calculator for running hypothetical scenarios before an exam or final. Notifications are delivered natively on iOS, Android, and web, or via email, and accounts can sign in with Google, Apple, Microsoft, or traditional email and password, with data exportable as JSON and importable from other planner tools. There is no advertising and no data reselling, and every feature вЂ” planning, grading, notes, sync, and notifications вЂ” is available for free to all users; the product is described as supported entirely by voluntary Patreon backers covering hosting and infrastructure costs. Helium targets individual students at every level: middle school, high school, college, university, graduate school, and homeschool learners who need a single tool to replace juggling a paper planner, a separate GPA calculator spreadsheet, and scattered class notes. Because it has no institutional licensing tier, it competes less with enterprise student-information systems and more with consumer planner and note-taking apps such as My Study Life, iStudiez Pro, Todoist used academically, and Google Calendar plus Notion combinations; Helium differentiates itself by combining calendar, grade calculation, and notes natively in one purpose-built academic product rather than requiring students to stitch together generic productivity apps, while remaining completely free and open source where most academic-planner competitors are freemium or subscription-based.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4cbf934b-aea7-4a55-98f6-4e21939c1ec3';

