-- в”Ђв”Ђ INGInious в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source platform for automated grading of programming assignments, built at UCLouvain with Docker-based secure code execution.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Louvain-la-Neuve, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$German$q$, $q$Portuguese$q$, $q$Dutch$q$, $q$Greek$q$, $q$Hebrew$q$, $q$Vietnamese$q$, $q$Norwegian$q$]::text[],
  seo_title = COALESCE($q$INGInious Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$INGInious is a free, open-source automated grading platform for programming courses. See its Docker-based features, LMS integrations, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$INGInious is a free, open-source platform for the secure, automated assessment of programming assignments, describing itself as an online 'teaching assistant' that lets students test their code and receive non-binary feedback on how to improve. It was developed by the INGI computer science department at the Universite catholique de Louvain (UCLouvain) in Louvain-la-Neuve, Belgium, with development underway since 2014 and partial funding from the Walloon region of Belgium; the project has also received sponsorship support from Zulip. INGInious is written in Python and uses Docker containers to execute untrusted, student-submitted code in isolated, secure sandboxes, preventing malicious or broken code from affecting the host system, while MongoDB is used to store and track student submissions and grading history. The platform is released under the AGPL (GNU Affero General Public License), keeping it fully open source and modifiable, with the current stable release at version 0.9.3 and source code maintained publicly on GitHub under the INGInious organization. Functionally, teachers write test suites (using their own custom test scripts) that automatically grade code submissions and return detailed, non-binary feedback rather than a simple pass/fail result, helping students understand not just whether their code worked but how to improve it. INGInious supports 10 interface languages including English, French, Spanish, German, Portuguese, Dutch, Greek, Hebrew, Vietnamese, and Norwegian, reflecting its use across a diverse international base of universities and MOOC providers. It can run as a standalone platform or integrate with existing learning management systems through an LTI (Learning Tools Interoperability) module, allowing it to plug directly into Open edX and Moodle courses as an external, automated grader вЂ” a design that has made it particularly popular for massive open online courses (MOOCs) and large introductory programming courses where manual grading of hundreds or thousands of submissions is impractical. Because it is self-hosted open-source software, there is no commercial pricing: institutions download INGInious from GitHub and deploy it on their own servers or infrastructure, configuring Docker-based grading environments for whatever programming languages and frameworks their courses require. INGInious's target audience is computer science departments, university instructors, and MOOC platform operators who need a rigorous, secure, and scalable way to auto-grade programming exercises for students ranging from complete beginners to advanced university-level learners. Its closest competitors in the automated programming-assessment space include Gradescope's autograder, CodeGrade, Vocareum, and Web-CAT, as well as MOOC-native graders built into platforms like Open edX itself; INGInious differentiates itself by being entirely free, open source, and self-hostable under AGPL, by its Docker-based sandboxing approach to safely executing arbitrary student code, and by its academic pedigree as a tool built and used within a research university (UCLouvain) rather than a commercial ed-tech vendor, making it a natural fit for institutions that want full control over their grading infrastructure and student data without per-seat licensing costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
