INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Color-coded calendar$q$, $q$Month, Week, Day, and Agenda views with drag-and-drop scheduling for classes and assignments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Real-time grade calculator$q$, $q$Grades recalculate instantly as work is entered, broken down by class and assignment category.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$At-risk class alerts$q$, $q$Flags classes that fall below a student-defined grade threshold so problems get caught early.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Progress vs. pace indicator$q$, $q$Shows whether a student is ahead of, on track with, or behind their target pace in a class.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$What-grade-do-I-need calculator$q$, $q$Models hypothetical future scores to show what is needed on remaining work to hit a target grade.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Two-way calendar sync$q$, $q$Syncs with Google Calendar, Apple Calendar, and iCal feeds so schedules stay consistent everywhere.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Linked notebook$q$, $q$Rich, searchable notes with headings, lists, quotes, and links, tied to specific classes or assignments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Cross-platform apps$q$, $q$Native apps for web, iOS, and Android with single sign-in and instant cross-device sync.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Completely free with no paid tiers or ads$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Real-time grade calculation and at-risk alerts are unusually sophisticated for a free planner$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Open source, so the codebase is publicly auditable$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Available natively on web, iOS, and Android with full sync$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$No data selling or advertising business model$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$No institutional or school-wide licensing tier for administrators$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Maintained largely by a single developer, which can affect support response times$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Relies on voluntary donations, raising long-term sustainability questions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Lacks collaboration features found in some paid study-group tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$No desktop-native application, only web and mobile$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Is Helium really free?$q$, $q$Yes. Helium is free for all students on web, iOS, and Android, with every feature included. It is funded through voluntary Patreon and GitHub Sponsors contributions rather than subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Who created Helium?$q$, $q$Helium was created and is maintained by independent developer Alex Laird, building on his earlier Get Organized desktop planner.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Does Helium sync with Google Calendar?$q$, $q$Yes, Helium offers two-way synchronization with Google Calendar, Apple Calendar, and generic iCal feeds.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Is Helium open source?$q$, $q$Yes, Helium's code is published on GitHub under the heliumedu organization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$What platforms does Helium support?$q$, $q$Helium is available as a web application and as native iOS and Android apps, with accounts syncing across all of them.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Can Helium calculate what grade I need on a final?$q$, $q$Yes, Helium includes a 'what grade do I need' calculator that models hypothetical scores against your current grade.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Tracking coursework and deadlines$q$, $q$Students use Helium's calendar and Todos views to manage classes, assignments, and due dates in one color-coded workspace.$q$, $q$High school and college students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Real-time GPA monitoring$q$, $q$Students enter grades as they receive them and Helium instantly recalculates class and overall grades, flagging at-risk classes.$q$, $q$Students tracking academic performance$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Class notes tied to assignments$q$, $q$Students keep searchable, formatted notes linked directly to the class or assignment they relate to instead of a separate notes app.$q$, $q$Students and homeschool learners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["All calendar and planning features","Real-time grade calculator","At-risk class alerts","Two-way calendar sync","Notebook and notifications","Web, iOS, and Android apps"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Helium is a free, open-source student planner and academic calendar built by independent developer Alex Laird under the HeliumEdu project. It gives students one place to manage classes, assignments, grades, and notes, replacing the usual mix of a paper planner, a spreadsheet for GPA tracking, and a separate notes app. The product is a modern rebuild of Get Organized, an earlier Java desktop planner from the same developer that was used by tens of thousands of students, now reimagined as a synced web and mobile experience.$q$, $q$The app is available on the web and as native iOS and Android apps, with accounts syncing instantly across devices. Rather than charging for premium tiers, Helium is funded entirely through voluntary community support on Patreon and GitHub Sponsors, which covers hosting and ongoing development costs while keeping every feature free and ad-free for students.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Helium is a color-coded calendar with Month, Week, Day, and Agenda views that lets students drag and drop classes and assignments to reschedule work quickly. A dedicated Todos view keeps day-to-day tasks separate from long-term academic planning, and a rich notebook lets students attach formatted notes вЂ” with headings, lists, quotes, and links вЂ” directly to a specific class or assignment, then search across the whole library later.$q$, $q$Helium's most distinctive feature is real-time grade tracking: as assignments are graded, Helium recalculates overall and per-category grades instantly, flags classes as 'at risk' when they fall below a set threshold, and shows whether a student is ahead of, on track with, or behind their target pace. A built-in 'what grade do I need' calculator lets students model hypothetical scores before turning in a final assignment or sitting an exam. Two-way sync with Google Calendar, Apple Calendar, and iCal feeds keeps everything current with a student's existing scheduling tools, and push notifications on iOS, Android, and web (or email) provide reminders for upcoming deadlines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Helium has no paid tiers. Every feature вЂ” the calendar, grade calculator, notebook, calendar sync, and notifications вЂ” is available at no cost to any student who signs up, whether via web, iOS, or Android.$q$, $q$Instead of a subscription model, Helium is sustained by voluntary contributions through Patreon and GitHub Sponsors, which fund the infrastructure needed to keep the service running for the thousands of students who rely on it daily. There is no ad-supported tier and no paid upgrade path, making it a genuinely free alternative to subscription-based student planners.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cbf934b-aea7-4a55-98f6-4e21939c1ec3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
