INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Event and timetable management$q$, $q$Create and configure conferences, meetings, and lectures with flexible, multi-session timetables.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Registration management$q$, $q$Collect and manage participant registration for events of any size.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Multi-level access control$q$, $q$Granular permissions determine who can view, edit, or manage specific event content and materials.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Paper review workflow$q$, $q$Structured submission and peer-review process for academic and scientific conference papers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Document and material archival$q$, $q$Permanently store presentations, slides, and papers alongside event metadata for long-term reference.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Room and resource booking$q$, $q$Coordinate physical meeting rooms and resources across an organization's facilities.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Self-hosted deployment$q$, $q$Runs on an organization's own infrastructure via Python, Flask, and PostgreSQL for full data control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Open API and integrations$q$, $q$Supports integration with collaborative tools and external systems through its API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Battle-tested at massive scale by CERN and the United Nations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Combines scheduling, paper review, and archival in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Active global community with contributions from over 100 developers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Full data control and customization via self-hosting$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Requires self-hosting and server administration expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$No official commercial support or hosted SaaS edition from CERN$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Interface reflects its scientific-conference origins, less suited to consumer event marketing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Steeper learning curve than lightweight ticketing tools like Eventbrite$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Room booking and paper review features add complexity for simple events$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Is Indico free to use?$q$, $q$Yes, Indico is fully open source under the MIT license and free to download and self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Who built Indico?$q$, $q$Indico originated from a 2002 European Union-funded project and has been developed and financed by CERN since 2004.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Does Indico offer a hosted cloud version?$q$, $q$There is no official CERN-run SaaS edition; organizations self-host Indico on their own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$What is Indico built with?$q$, $q$Indico is built in Python using the Flask framework, SQLAlchemy with PostgreSQL for data storage, and React for the web interface.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Who uses Indico besides CERN?$q$, $q$Indico is used by more than 300 organizations worldwide, including the United Nations and the Max Planck Institute for Physics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Can Indico handle academic paper submissions?$q$, $q$Yes, Indico includes a structured paper submission and peer-review workflow for academic conferences.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Scientific conference organization$q$, $q$Research institutions use Indico to run large conferences with timetables, registration, and paper review.$q$, $q$Universities and research labs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Institutional meeting and room management$q$, $q$Large organizations coordinate hundreds of meeting rooms and recurring meetings through Indico's booking system.$q$, $q$International organizations and enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Long-term event archival$q$, $q$Organizations use Indico to permanently archive presentations, papers, and event metadata for future reference.$q$, $q$Academic and scientific institutions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT license","Event, timetable, and registration management","Paper review workflow","Room booking","Document archival","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Indico is an open-source event management platform that grew out of a European Union-funded research project at CERN in 2002 and has been developed and financed by CERN since 2004. Originally built to organize the physics laboratory's own meetings and conferences, it has since become a globally adopted platform used by research institutions, universities, and international organizations including the United Nations.$q$, $q$The software is MIT-licensed, built on Python and Flask with a PostgreSQL database and a React front end, and its source code is publicly maintained on GitHub. Because there is no official hosted SaaS edition, organizations run Indico on their own servers, giving them full control over data and customization at the cost of managing their own deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Indico covers the complete lifecycle of an event: creating flexible timetables for conferences, meetings, and lectures; managing attendee registration; and controlling multi-level access permissions for who can view, edit, or manage specific event content. For academic and scientific conferences, it includes a structured paper submission and peer-review workflow, letting organizers collect, review, and score submitted papers within the same system used to run the event itself.$q$, $q$Beyond scheduling, Indico provides document management for archiving presentations, slides, and papers permanently alongside event metadata, plus room and resource booking for physical meeting spaces вЂ” CERN alone uses Indico to coordinate over 200 meeting and conference rooms. This combination of scheduling, review, archival, and room booking in a single open-source system is what distinguishes Indico from lighter-weight ticketing tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Indico is free and open source under the MIT license. There is no commercial pricing tier or official CERN-hosted SaaS product; organizations download the software from GitHub and deploy it on their own infrastructure.$q$, $q$Because it is self-hosted, the real cost to an institution is the infrastructure and system-administration effort required to run and maintain an instance, not a licensing fee. This makes Indico attractive to research institutions and international bodies that already operate their own IT infrastructure and want full control and long-term data ownership.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('367a6bce-9b7f-4b10-9faa-47430b894121', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Secrets storage and syncing$q$, $q$Centralized storage for API keys, environment variables, and credentials synced across environments and services.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Secret scanning and leak prevention$q$, $q$Detects credentials accidentally committed to source code before they become a breach.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Kubernetes Operator and Agent$q$, $q$Injects secrets directly into Kubernetes workloads and running applications without hardcoding values.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Secret versioning and rotation$q$, $q$Point-in-time recovery of past secret values plus automated rotation of credentials on a schedule.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Role-based access control$q$, $q$Fine-grained permissions determine which identities can read, write, or manage specific secrets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Dynamic secrets$q$, $q$Generates short-lived, on-demand credentials for databases and cloud providers to reduce standing access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$SAML SSO and SCIM$q$, $q$Enterprise identity integration for single sign-on and automated user provisioning.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$CLI, SDKs, and REST API$q$, $q$Programmatic access for integrating secrets management into CI/CD pipelines and custom tooling.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Open-source core with a genuinely usable free self-hosted tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Flexible identity-based pricing covers both humans and machine accounts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Strong integration ecosystem with AWS, Vercel, GitHub Actions, and Kubernetes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Backed by well-known investors including Elad Gil and Y Combinator$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Enterprise tier includes HSM, KMIP, and SCIM for regulated industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Several security-critical features like RBAC and SSO require a paid license even when self-hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Per-identity pricing can scale quickly for organizations with many machine accounts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Enterprise pricing is custom and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Younger company with a shorter track record than established players like HashiCorp Vault$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Advanced features like dynamic secrets are Enterprise-only$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Is Infisical free to use?$q$, $q$Yes, Infisical has a free tier covering up to 5 identities, 3 projects, and the full open-source feature set, including self-hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Who founded Infisical?$q$, $q$Infisical was founded in 2022 by Tony Dang, Vlad Matsiiako, and Maidul Islam, and went through Y Combinator's W23 batch.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$How much does Infisical Pro cost?$q$, $q$Infisical Pro costs $18 per month per identity, where an identity can be a human user or a machine/service account.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Can I self-host Infisical for free?$q$, $q$Yes, the MIT-licensed core can be self-hosted at no cost, though features like RBAC and SAML SSO require a paid license key.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Has Infisical raised funding?$q$, $q$Yes, Infisical raised a $16 million Series A in June 2025 led by Elad Gil, with participation from Y Combinator and Gradient, bringing total funding to roughly $19 million.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$What are Infisical's main competitors?$q$, $q$Infisical competes with HashiCorp Vault, AWS Secrets Manager, and Doppler in the secrets management space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Centralizing environment variables$q$, $q$Development teams replace scattered .env files with a single synced source of truth for secrets across environments.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Kubernetes secret injection$q$, $q$Platform teams use the Kubernetes Operator to inject secrets into pods without storing them in manifests.$q$, $q$DevOps and platform engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Compliance-grade access control$q$, $q$Regulated organizations use RBAC, SSO, and audit logs to control and record who can access sensitive credentials.$q$, $q$Enterprises in regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 5 identities","3 projects, 3 environments","Full open-source feature set","Self-hosting or Infisical Cloud","Secret scanning and leak prevention","Community Slack support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Pro$q$, $q$$18/identity$q$, $q$Monthly$q$, NULL, $q$["Everything in Free","Secret versioning and point-in-time recovery","Role-based access control","Automated secret rotation","SAML SSO and IP allowlisting","90-day audit log retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual (custom)$q$, NULL, $q$["Everything in Pro","SCIM and LDAP authentication","Dynamic secrets and AI security advisor","Approval workflows","KMIP and HSM/KMS support","99.99% SLA and dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Infisical is an open-source secrets management platform founded in 2022 by Tony Dang, Vlad Matsiiako, and Maidul Islam, who took the company through Y Combinator's W23 batch before raising a $16 million Series A led by Elad Gil in 2025. Headquartered in San Francisco, Infisical helps engineering teams store, sync, and rotate API keys, environment variables, and certificates instead of scattering them across .env files, chat messages, or hardcoded config.$q$, $q$The platform's core is MIT-licensed and can be self-hosted for free or run as a managed Infisical Cloud service, giving teams flexibility over where their most sensitive data lives. It ships with a dashboard, REST API, CLI, SDKs, a Kubernetes Operator, and a background agent that injects secrets into running applications at runtime.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Infisical's free, open-source core covers secret storage, referencing and overrides between environments, secret scanning to catch leaked credentials in code, webhooks for automation, and two-factor authentication, along with pre-built integrations for AWS, Vercel, GitHub Actions, and other common infrastructure tools. This means teams can run a fully self-hosted secrets manager without paying for a license, which is unusual among competitors.$q$, $q$Paid Pro and Enterprise tiers add the controls larger teams need for compliance and operational safety: secret versioning with point-in-time recovery, role-based access control, automated secret rotation, SAML SSO, temporary just-in-time access, dynamic secrets that generate short-lived credentials on demand, SCIM and LDAP provisioning, and hardware security module (HSM) and KMIP support for regulated environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Infisical prices around 'identities' вЂ” counting both human team members and machine or service accounts вЂ” rather than traditional seats. The Free plan supports up to 5 identities, 3 projects, and 3 environments with the full open-source feature set and the option to self-host at no cost.$q$, $q$The Pro plan costs $18 per identity per month and adds versioning, RBAC, rotation, SSO, IP allowlisting, and audit logs, while Enterprise moves to custom pricing for SCIM, dynamic secrets, dedicated infrastructure, HSM support, and a 99.99% SLA. Notably, several advanced features like RBAC and SAML SSO require a paid license key even when self-hosting on your own servers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('870d8f7e-4a30-42b3-8999-2b52c10af200', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
