INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Purpose-built time-series storage$q$, $q$Columnar storage engine (IOx) optimized for high-throughput writes and fast time-range queries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$SQL, InfluxQL, and Flux support$q$, $q$Query time-series data using SQL, the original InfluxQL, or the Flux functional query language.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Telegraf data collection$q$, $q$Open-source agent with plugins for hundreds of data sources to ingest metrics without custom code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Downsampling and continuous queries$q$, $q$Automatically aggregate and reduce older data to control long-term storage costs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Native alerting$q$, $q$Built-in notification rules trigger alerts based on thresholds and anomalies in incoming data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Multiple deployment tiers$q$, $q$Choose from free, usage-based serverless, annual committed-use, or dedicated single-tenant infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Client libraries$q$, $q$Official SDKs for major programming languages to read and write time-series data programmatically.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$SAML/SSO and uptime SLA add-ons$q$, $q$Enterprise identity integration and service-level guarantees available on paid usage-based and annual plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Purpose-built for time-series workloads with strong write throughput$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Flexible pricing spans free prototyping through dedicated enterprise infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Telegraf ecosystem simplifies data collection from hundreds of sources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Backed by a well-funded, established vendor with over a decade in the market$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Supports SQL alongside its native InfluxQL and Flux query languages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Usage-based pricing can become expensive and unpredictable at high ingestion volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Dedicated and Annual tiers require contacting sales rather than transparent self-serve pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Migration between Flux, InfluxQL, and SQL query models can create a learning curve$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Free tier's rate limits are restrictive for anything beyond small prototypes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Competes with free, self-hosted alternatives like Prometheus for basic metrics use cases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Is InfluxDB Cloud free?$q$, $q$InfluxDB Cloud has a free, rate-limited tier (5MB writes and 300MB queries per 5 minutes, 30-day retention) suitable for learning and prototyping.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Who founded InfluxData?$q$, $q$InfluxData was founded in 2012 by Paul Dix and Todd Persen, initially operating as Errplane before rebranding in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$How is InfluxDB Cloud priced?$q$, $q$Beyond the free tier, InfluxDB Cloud uses usage-based pricing charged per MB ingested, per query volume, per GB-hour stored, and per GB of egress, with annual committed-use and dedicated infrastructure options for larger workloads.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$What is InfluxDB Cloud Dedicated?$q$, $q$It is a single-tenant, enterprise-grade deployment offering workload isolation and enhanced SLAs, typically custom-quoted starting around $50,000 per year.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$What query languages does InfluxDB Cloud support?$q$, $q$InfluxDB Cloud supports SQL, the original InfluxQL, and the Flux functional query language.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$What is InfluxDB Cloud commonly used for?$q$, $q$It is commonly used for infrastructure and application monitoring, IoT sensor data, financial market data, and industrial equipment telemetry.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Infrastructure and application monitoring$q$, $q$DevOps teams ingest metrics from servers and applications via Telegraf and build dashboards and alerts on top of InfluxDB Cloud.$q$, $q$DevOps and observability teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$IoT sensor data ingestion$q$, $q$IoT platforms stream high-volume sensor telemetry into InfluxDB Cloud for real-time analysis and long-term storage.$q$, $q$IoT and industrial companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Financial and market data tracking$q$, $q$Financial services store timestamped market data for real-time and historical analysis at scale.$q$, $q$Financial services and trading platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["5MB writes / 300MB queries per 5 min","30-day data retention","2 databases","2 notification rules"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Usage-Based$q$, $q$Pay-as-you-go$q$, $q$Monthly$q$, NULL, $q$["Unlimited retention and databases","$0.0025/MB ingestion","$0.012 per 100 queries","$0.002/GB-hour storage","Optional uptime SLA and SAML/SSO"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Annual$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Unlimited writes, queries, retention, databases","Uptime SLA included","SAML/SSO included","Dedicated customer success"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$Dedicated$q$, $q$Custom pricing (from approx. $50,000/year)$q$, $q$Annual$q$, NULL, $q$["Single-tenant infrastructure","Workload isolation","No applied service quotas","Optional private networking"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$InfluxDB Cloud is the managed, cloud-hosted edition of InfluxDB, the purpose-built time-series database created by InfluxData. Founded in 2012 by Paul Dix and Todd Persen (initially under the name Errplane), InfluxData is headquartered in San Francisco and has raised roughly $120 million in venture funding to build out InfluxDB and its cloud infrastructure, including the newer Rust-based IOx storage engine.$q$, $q$The platform is designed specifically for timestamped data вЂ” metrics, events, and sensor readings вЂ” that pours in continuously from infrastructure, applications, and IoT devices. Rather than a single fixed offering, InfluxDB Cloud spans multiple deployment models, from a free rate-limited tier for experimentation to dedicated single-tenant infrastructure for large-scale production workloads.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$InfluxDB Cloud supports both the InfluxQL and newer SQL query languages, along with the original Flux language, giving teams flexibility in how they analyze time-series data. Telegraf, InfluxData's open-source collection agent, ships with plugins for hundreds of data sources, making it straightforward to pipe in metrics from servers, containers, sensors, and third-party APIs without custom ingestion code.$q$, $q$The platform includes built-in downsampling and continuous query capabilities to manage long-term storage costs, native alerting and notification rules, and a columnar storage architecture (via the IOx engine) optimized for high write throughput and fast time-range queries at scale. Deployment options range from shared serverless infrastructure to fully dedicated, single-tenant environments for workload isolation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan is rate-limited to 5MB of writes and 300MB of queries per 5-minute window, with 30-day retention and up to 2 databases вЂ” enough for learning InfluxDB or prototyping small projects. The Usage-Based plan removes those retention and database caps and charges per unit consumed: $0.0025 per MB ingested, $0.012 per 100 queries, $0.002 per GB-hour stored, and $0.09 per GB of egress.$q$, $q$For committed production workloads, Annual plans offer volume discounts with unlimited writes, queries, and retention plus an uptime SLA and dedicated customer success, while InfluxDB Cloud Dedicated provides single-tenant infrastructure typically starting around $50,000 per year. Most production deployments across all tiers land between $5,000 and $75,000 annually, with the largest dedicated deployments exceeding $150,000.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c8ef1e9c-3e2d-43bd-b790-a687f3d10cd5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Automated code grading$q$, $q$Instructors write custom test suites that automatically grade student programming submissions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Non-binary feedback$q$, $q$Returns detailed feedback on submissions rather than a simple pass/fail result, helping students improve.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Docker-based sandboxing$q$, $q$Executes untrusted student code in isolated Docker containers to keep the host system secure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$LMS integration via LTI$q$, $q$Plugs into Open edX and Moodle as an external automated grader through the LTI standard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$MOOC-scale support$q$, $q$Designed to handle large volumes of concurrent submissions typical of massive open online courses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Multi-language interface$q$, $q$Available in 10 languages including English, French, Spanish, German, and Dutch.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Submission tracking$q$, $q$Stores and tracks the full history of student submissions and grades using MongoDB.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Self-hosted deployment$q$, $q$Fully open source under AGPL, deployable on institution-owned infrastructure with no licensing fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Completely free and open source under AGPL$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Secure Docker-based sandboxing for running untrusted student code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Provides detailed, non-binary feedback rather than simple pass/fail grading$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Integrates with existing LMS platforms like Moodle and Open edX via LTI$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Proven at MOOC scale for large introductory programming courses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Requires self-hosting and Docker/MongoDB infrastructure expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$No official commercial support channel for institutions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Interface and workflow can require setup time for instructors unfamiliar with test-suite scripting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Smaller community and ecosystem compared to commercial autograders like Gradescope$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Documentation is geared toward technical administrators rather than casual instructors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Is INGInious free?$q$, $q$Yes, INGInious is fully free and open source under the AGPL license with no commercial pricing tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Who built INGInious?$q$, $q$INGInious was developed by the INGI computer science department at the Universite catholique de Louvain (UCLouvain) in Belgium, with development ongoing since 2014.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$How does INGInious keep student code execution safe?$q$, $q$It runs untrusted student submissions inside isolated Docker containers, preventing them from affecting the host system.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Can INGInious integrate with Moodle or edX?$q$, $q$Yes, INGInious provides an LTI module that lets it function as an external automated grader within Open edX or Moodle courses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$What is INGInious best suited for?$q$, $q$It is best suited for automated grading of programming assignments in university courses and massive open online courses (MOOCs).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$What languages does INGInious support?$q$, $q$The platform's interface supports 10 languages, including English, French, Spanish, German, Portuguese, Dutch, Greek, Hebrew, Vietnamese, and Norwegian.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Automated programming assignment grading$q$, $q$University instructors use INGInious to automatically grade coding assignments and give students detailed feedback at scale.$q$, $q$Computer science instructors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$MOOC-scale code assessment$q$, $q$MOOC platforms use INGInious to handle automated grading of programming exercises for thousands of concurrent learners.$q$, $q$MOOC providers and large online courses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$LMS-integrated grading$q$, $q$Institutions plug INGInious into existing Moodle or Open edX deployments as an external grader via LTI.$q$, $q$Universities with existing LMS infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPL","Docker-based secure code execution","Automated grading and feedback","LTI integration for Moodle and Open edX","10 supported languages","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$INGInious is a free, open-source platform for automated assessment of programming assignments, built by the INGI computer science department at the Universite catholique de Louvain (UCLouvain) in Belgium since 2014, with partial funding from the Walloon region. It positions itself as an online teaching assistant, letting students submit code and receive detailed, non-binary feedback rather than a simple pass or fail.$q$, $q$The platform is written in Python and released under the AGPL license, with source code maintained on GitHub. It uses Docker to execute untrusted student code in isolated, secure containers and MongoDB to track submissions and grading history, giving institutions a self-hostable grading engine they can run entirely on their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, INGInious lets instructors write custom automated test suites that grade student code submissions and return granular feedback explaining what worked, what did not, and why, rather than a binary correct/incorrect result. This is especially valuable for large introductory programming courses and massive open online courses (MOOCs), where manual grading of every submission is impractical.$q$, $q$Because grading runs inside Docker containers, INGInious can safely execute arbitrary, potentially broken or malicious student code without risking the host system. The platform also ships an LTI integration module, allowing it to plug into existing learning management systems like Open edX and Moodle as an external grader, and it supports 10 interface languages, reflecting adoption across a broad international base of universities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$INGInious is entirely free and open source under the AGPL license. There are no paid tiers, subscriptions, or commercial licensing fees; institutions download the platform from GitHub and self-host it on their own servers.$q$, $q$The only real cost to a school or university is the infrastructure needed to run the Docker-based grading environment and MongoDB database, plus the system-administration effort to configure test suites for each course's programming language and toolchain.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
