INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('455123f9-8dc8-466a-b9ac-7b565c629ede', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Native SVG editing$q$, $q$Built around the Scalable Vector Graphics standard as its native file format, with a faithful, complete SVG implementation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Bezier pen and node editing$q$, $q$A five-mode Bezier pen tool plus precise node editing for manipulating path points and handles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Pressure-sensitive drawing tools$q$, $q$Freehand pencil and calligraphy brush tools support graphics tablets with pressure sensitivity and smoothing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Shape primitives$q$, $q$Rectangles, ellipses, arcs, 3D boxes with adjustable perspective, stars, polygons, and spirals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Filter gallery$q$, $q$Browse and preview built-in visual filters for effects like blurs, shadows, and textures.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Extension system$q$, $q$Plugin architecture supporting community-built path tools, export formats, and automation scripts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Broad file format support$q$, $q$Imports and exports AI, EPS, PDF, PostScript, and PNG in addition to native SVG.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Cross-platform availability$q$, $q$Runs natively on Windows, macOS, and Linux.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Faithful, deep implementation of the open SVG standard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Extensible plugin architecture with an active community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Cross-platform support for Windows, macOS, and Linux$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Two decades of continuous development and stability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Interface feels dated compared to modern commercial tools like Affinity Designer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$No official cloud collaboration or real-time multi-user editing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Performance can lag on very complex files with many objects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Learning curve for users coming from Adobe Illustrator due to UI differences$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$No official mobile app for iOS or Android$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Is Inkscape completely free?$q$, $q$Yes, Inkscape is free and open source under the GPL license with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$When was Inkscape created?$q$, $q$Inkscape began in 2003 as a fork of the earlier Sodipodi project, led by developers Ted Gould, Bryce Harrington, Nathan Hurst, and MenTaLguY.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$What file formats does Inkscape support?$q$, $q$Inkscape natively uses SVG and can import and export Adobe Illustrator (AI), EPS, PDF, PostScript, and PNG files.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Is Inkscape a good alternative to Adobe Illustrator?$q$, $q$Yes, Inkscape is widely used as a free alternative to Illustrator, though its interface and workflow differ and it lacks Illustrator's cloud collaboration features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$What operating systems does Inkscape support?$q$, $q$Inkscape runs natively on Windows, macOS, and Linux.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Who maintains Inkscape?$q$, $q$Inkscape is maintained by a distributed volunteer open-source community rather than a single company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Logo and brand design$q$, $q$Designers create scalable logos and brand assets using Inkscape's precise vector and node-editing tools.$q$, $q$Freelance and in-house graphic designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Technical diagrams and flowcharts$q$, $q$Teams build technical illustrations, diagrams, and flowcharts that need to scale cleanly across print and screen.$q$, $q$Engineers and technical writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Print and packaging design$q$, $q$Designers use Inkscape's PDF and EPS support to prepare artwork for professional print and packaging production.$q$, $q$Print and packaging designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full vector editing toolset","Native SVG support","Extension and plugin system","AI, EPS, PDF, PS, PNG import/export","Windows, macOS, and Linux support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Inkscape is a free, open-source vector graphics editor that began in 2003 as a fork of the earlier Sodipodi project, led by developers Ted Gould, Bryce Harrington, Nathan Hurst, and MenTaLguY. Where Sodipodi aimed to be a general-purpose editor, Inkscape committed from the start to a faithful, complete implementation of the SVG (Scalable Vector Graphics) standard, which remains its native file format today.$q$, $q$Released under the GPL license, Inkscape has no corporate owner and is maintained entirely by a distributed volunteer community; its source repository has moved over the years from SourceForge to Launchpad and finally to GitLab in 2017. It runs natively on Windows, macOS, and Linux and remains completely free for personal, educational, and commercial use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Inkscape provides a complete vector-editing toolkit built around shape primitives (rectangles, ellipses, arcs, 3D boxes with adjustable perspective, stars, polygons, and spirals), a Bezier pen tool with five distinct drawing modes, a pressure-sensitive freehand pencil for graphics-tablet input, and a calligraphy brush tool for natural-feeling strokes. A dedicated node-editing tool allows precise manipulation of individual path points, Bezier handles, and node alignment for fine-tuning any shape.$q$, $q$Version 1.4 introduced a redesigned filter gallery for browsing and previewing Inkscape's built-in visual filters, and the software supports a rich extension system that lets community developers add custom path-editing tools, export formats, and automation scripts. Inkscape natively supports SVG but can also import and export Adobe Illustrator (AI), EPS, PDF, PostScript, and PNG files, making it interoperable with both vector and raster workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Inkscape is entirely free under the GPL license with no paid tiers, subscriptions, or licensing fees of any kind. Every feature, including all drawing tools, filters, and file format support, is available to every user at no cost.$q$, $q$Because it has no corporate ownership, there is no premium upsell path or enterprise licensing option; the project is instead sustained through community contributions and voluntary donations that support ongoing development and infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
