INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4dd8f19-6a19-464f-aa03-b7df8213b789', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Durable step functions$q$, $q$Each step's result is checkpointed so functions resume from the last successful step after a failure instead of restarting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Event-driven triggers$q$, $q$A single event can fan out and trigger multiple functions across an application.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Built-in scheduling$q$, $q$Supports cron-style recurring jobs and delayed, one-off scheduled execution.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Flow control$q$, $q$Concurrency limits, throttling, and rate limiting protect downstream systems and APIs from overload.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Real-time observability dashboard$q$, $q$Monitor function execution, traces, and failures as they happen.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Serverless-native execution$q$, $q$Runs on platforms like Vercel and AWS Lambda without requiring dedicated worker infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Multi-language SDKs$q$, $q$Integrates directly into existing application code across popular languages and frameworks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$AI agent workflow support$q$, $q$Purpose-built patterns for orchestrating multi-step AI agent pipelines reliably.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$No separate workflow server needed; integrates directly into existing app code$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Automatic retries and checkpointing simplify building reliable multi-step processes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Runs natively on serverless platforms like Vercel and AWS Lambda$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Generous free Hobby tier for individual developers to fully evaluate the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Backed by well-known investors including Andreessen Horowitz and Guillermo Rauch$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Usage-based overage pricing can become costly at high execution volumes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$SAML SSO and RBAC are Enterprise-only, gated behind custom pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Smaller ecosystem and community than established alternatives like Temporal$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Trace retention is limited to 24 hours on the free Hobby plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Relies on external infrastructure providers for actual compute execution$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Is Inngest free to use?$q$, $q$Yes, Inngest's Hobby plan is free with no credit card required, including 50,000 monthly executions and 5 concurrent executions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Who founded Inngest?$q$, $q$Inngest was founded in 2021 by CEO Tony Holdstock-Brown and co-founder/CTO Dan Farrelly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$How much does Inngest Pro cost?$q$, $q$The Pro plan starts at $99 per month with metered usage-based pricing for executions, concurrency, and events above the included limits.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$What is 'durable execution' in Inngest?$q$, $q$It means each step of a function is checkpointed by Inngest's runtime, so if a failure occurs, execution resumes from the last successful step instead of starting over.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Can Inngest run on serverless platforms?$q$, $q$Yes, Inngest is designed to run on serverless platforms like Vercel and AWS Lambda without requiring dedicated worker infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$How much funding has Inngest raised?$q$, $q$Inngest has raised roughly $34 million total, including a round led by Andreessen Horowitz and a subsequent $21 million Series A.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$AI agent orchestration$q$, $q$Developers use Inngest's durable step functions to reliably run multi-step AI agent pipelines that can recover from failures.$q$, $q$AI application developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Background job processing$q$, $q$Teams offload long-running or asynchronous tasks like email sending and data processing to Inngest instead of managing their own queues.$q$, $q$Backend and full-stack developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Scheduled and event-driven workflows$q$, $q$Companies trigger multi-step workflows from application events or cron schedules, such as onboarding sequences or nightly data syncs.$q$, $q$SaaS and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Hobby$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["50,000 monthly executions","5 concurrent executions","500,000 events ingested","3 team users","24-hour trace retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Pro$q$, $q$$99/month$q$, $q$Monthly$q$, NULL, $q$["1M+ monthly executions","100+ concurrent executions","5M+ events ingested","15 team users","7-day trace retention","Metered overage pricing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual (custom)$q$, NULL, $q$["Custom execution and concurrency limits","SAML SSO and RBAC","90-day trace retention","50 team users","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Inngest is a durable execution platform, founded in 2021 by CEO Tony Holdstock-Brown and CTO Dan Farrelly and headquartered in San Francisco, that helps developers build reliable event-driven workflows and background jobs. Its core model treats functions as a series of individually durable steps: each step's result is checkpointed, so if a failure occurs mid-execution, the function resumes from the last successful step instead of starting over.$q$, $q$The company has raised roughly $34 million in venture funding, including a 2024 round led by Andreessen Horowitz with participation from Vercel CEO Guillermo Rauch, and a subsequent $21 million Series A. Inngest is designed to run on virtually any platform, including serverless environments like Vercel and AWS Lambda, without developers needing to operate their own message queues or worker infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Inngest's step functions automatically retry and checkpoint progress, so multi-step processes like AI agent pipelines, onboarding flows, and data pipelines survive failures without manual intervention. Event-driven triggers let a single event fan out to multiple functions, and built-in scheduling supports both cron-style recurring jobs and one-off delayed execution.$q$, $q$Flow control features including concurrency limits, throttling, and rate limiting protect downstream systems and APIs from being overwhelmed, while a real-time dashboard gives developers visibility into function execution, traces, and failures. SDKs integrate directly into existing application code across popular languages and frameworks, avoiding the need for a separate workflow server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Inngest's Hobby plan is free with no credit card required, including 50,000 monthly executions, 5 concurrent executions, 500,000 events, 3 team users, and 24-hour trace retention вЂ” enough for individual developers and small projects to fully evaluate the platform.$q$, $q$The Pro plan starts at $99 per month with roughly 1 million included executions and metered overage pricing beyond that ($50 per additional 1 million executions, among other overage rates), while Enterprise moves to custom pricing with SAML SSO, RBAC, 90-day trace retention, and dedicated support for teams running critical workflows at scale.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3acb1b38-990d-4851-be0b-cc32baa33857', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
