INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$How much does Insightly cost?$q$, $q$Insightly starts at $29 per user per month (Plus plan, billed annually), with Professional at $49 and Enterprise at $99 per user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Who founded Insightly?$q$, $q$Insightly was founded in 2009 in Perth, Australia, by Anthony Smith, and is now headquartered in San Francisco.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Is Insightly still an independent company?$q$, $q$No, Insightly was acquired by Crest Rock Partners in July 2024 and merged with Unbounce, now operating as Insightly CRM by Unbounce.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Does Insightly have mobile apps?$q$, $q$Yes, Insightly offers native mobile apps for both iOS and Android.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Does Insightly include project management?$q$, $q$Yes, Insightly natively combines CRM pipeline management with project management, letting teams convert closed deals into delivery projects.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Does Insightly offer a free trial?$q$, $q$Yes, all Insightly plans include a free 14-day trial.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Sales pipeline management$q$, $q$Sales teams track leads and opportunities through a Kanban-style pipeline from first contact to close.$q$, $q$Small and mid-sized sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Post-sale project delivery$q$, $q$Teams convert closed deals directly into tracked delivery projects without switching to a separate project management tool.$q$, $q$Service-based and B2B businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Marketing and CRM integration$q$, $q$Businesses combine Insightly's CRM with Unbounce's landing-page tools for connected lead capture and pipeline management.$q$, $q$SMB marketing and sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Plus$q$, $q$$29/user/month$q$, $q$Annual$q$, NULL, $q$["Lead and contact management","Project management","Advanced reports","Pre-built dashboards","100,000 records","10GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Professional$q$, $q$$49/user/month$q$, $q$Annual$q$, NULL, $q$["Everything in Plus","Lead assignment and routing","Workflow automation","AI Copilot","REST API and webhooks","250,000 records","100GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$Enterprise$q$, $q$$99/user/month$q$, $q$Annual$q$, NULL, $q$["Everything in Professional","Sandboxes","Products, pricebooks, and quotes","Comprehensive audit logging","Unlimited role-based permissions","500,000 records","250GB storage"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Insightly is a cloud-based CRM and project management platform built for small and mid-sized businesses, founded in 2009 in Perth, Australia, by Anthony Smith before growing into a San Francisco-headquartered SaaS company. In July 2024, Insightly was acquired by private equity firm Crest Rock Partners and merged with Unbounce, the landing-page and conversion-optimization platform, and now operates as 'Insightly CRM by Unbounce' within a combined go-to-market software suite.$q$, $q$By the time of the acquisition, Insightly reported more than 25,000 companies and over 1.5 million users on the platform. Its defining characteristic is combining traditional CRM sales-pipeline functionality with native project management, letting teams hand off a closed deal directly into a trackable delivery project rather than switching to a separate tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Insightly covers the full sales lifecycle: lead and contact management, web-to-lead capture, a Kanban-style pipeline view for opportunity management, email templates, and automated or customized email sending. Higher tiers add lead assignment and routing, workflow automation, bidirectional email sync, and an AI Copilot that can summarize and draft email replies.$q$, $q$What sets Insightly apart from many CRMs is its native project management module, which lets sales teams convert won deals directly into structured delivery projects with tasks and milestones. The platform also includes built-in business intelligence dashboards, configurable reporting, native iOS and Android mobile apps, and, on Professional and Enterprise tiers, REST API access and webhooks for custom integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e511c2d2-ceea-48e2-bbc6-ea875df08668', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Insightly offers three published tiers, all billed annually per user. Plus starts at $29 per user per month with core CRM and project management features, up to 100,000 records, and 10GB of storage. Professional, the recommended tier, is $49 per user per month and adds workflow automation, AI Copilot, REST API access, and bidirectional email sync, with 250,000 records and 100GB storage.$q$, $q$Enterprise is $99 per user per month and adds sandboxes, product/pricebook/quote management, comprehensive audit logging, and unlimited role-based permissions, with 500,000 records and 250GB storage. All plans include a free 14-day trial, though buyers should note that some reviews flag additional onboarding and premium support fees beyond the listed per-seat pricing.$q$]::text[], 2);
